import{_ as a,o as i,c as e,ae as p}from"./chunks/framework.Co1PSFSm.js";const t="/assets/image.BpdDvM8r.png",n="/assets/image-1.CU2u74rT.png",l="/assets/image-2.oSq15Orl.png",h="/assets/image-3.CPjyKJDu.png",m=JSON.parse('{"title":"如何利用github的pages服务搭建一个个人主页-第二篇-美化篇","description":"","frontmatter":{},"headers":[],"relativePath":"blog/如何利用github的pages服务搭建一个个人主页第二篇-美化篇.md","filePath":"blog/如何利用github的pages服务搭建一个个人主页第二篇-美化篇.md","lastUpdated":1780989183000}'),o={name:"blog/如何利用github的pages服务搭建一个个人主页第二篇-美化篇.md"};function r(d,s,c,g,b,u){return i(),e("div",null,[...s[0]||(s[0]=[p('<h1 id="如何利用github的pages服务搭建一个个人主页-第二篇-美化篇" tabindex="-1">如何利用github的pages服务搭建一个个人主页-第二篇-美化篇 <a class="header-anchor" href="#如何利用github的pages服务搭建一个个人主页-第二篇-美化篇" aria-label="Permalink to &quot;如何利用github的pages服务搭建一个个人主页-第二篇-美化篇&quot;">​</a></h1><p>在<a href="./如何利用github的pages服务搭建一个个人主页.html">上一篇文章</a>中，我们介绍了如何使用GitHub Pages搭建一个最简单的个人主页，但那个主页确实比较简陋，没有太多内容，没有美化、没有导航栏、大纲、没有自动化构建。今天我们来聊聊如何让我们的个人主页变得更美观、更实用。</p><h2 id="回顾-开启github-pages服务" tabindex="-1">回顾：开启GitHub Pages服务 <a class="header-anchor" href="#回顾-开启github-pages服务" aria-label="Permalink to &quot;回顾：开启GitHub Pages服务&quot;">​</a></h2><p>还记得吗？在上篇中，我们通过以下步骤开启了GitHub Pages服务：</p><ol><li>创建了名为 <code>{username}.github.io</code> 的特殊仓库</li><li>在仓库的 Settings &gt; Pages 中配置了部署源</li><li>将内容放在 <code>/docs</code> 目录下进行部署</li></ol><p><img src="'+t+'" alt="alt text"></p><h2 id="美化方案" tabindex="-1">美化方案 <a class="header-anchor" href="#美化方案" aria-label="Permalink to &quot;美化方案&quot;">​</a></h2><p>对于美化个人主页，我这里推荐两种方案：</p><h3 id="小白方案-基于publii" tabindex="-1">小白方案-基于Publii <a class="header-anchor" href="#小白方案-基于publii" aria-label="Permalink to &quot;小白方案-基于Publii&quot;">​</a></h3><p>Publii 是一款免费的桌面应用程序，专为创建静态网站而设计。它具有直观的界面和强大的功能，即使没有编码经验的人也能轻松使用。</p><p><strong>优点：</strong></p><ul><li>可视化编辑器，像编辑Word文档一样简单</li><li>预设的主题模板</li><li>无需代码知识</li></ul><p><strong>缺点：</strong></p><ul><li>功能相对有限</li><li>定制化程度不如手写代码高</li></ul><p><img src="'+n+'" alt="alt text"></p><h3 id="折腾方案-基于vitepress" tabindex="-1">折腾方案-基于VitePress <a class="header-anchor" href="#折腾方案-基于vitepress" aria-label="Permalink to &quot;折腾方案-基于VitePress&quot;">​</a></h3><p><img src="'+l+`" alt="alt text"></p><p>这正是我现在使用的方式，也是我个人推荐的方案。VitePress 是一个极简的静态站点生成器，由 Vue.js 和 Vite 驱动。</p><p>我已将我的个人主页开源，你可以直接使用我的模板，详情请查看项目 README：</p><p>地址：<a href="https://github.com/codemyhappy/codemyhappy.github.io" target="_blank" rel="noreferrer">https://github.com/codemyhappy/codemyhappy.github.io</a></p><h4 id="基本使用方法" tabindex="-1">基本使用方法 <a class="header-anchor" href="#基本使用方法" aria-label="Permalink to &quot;基本使用方法&quot;">​</a></h4><blockquote><p>需要下载<a href="https://nodejs.org/en/" target="_blank" rel="noreferrer">Node.js</a> 和<a href="https://git-scm.com/" target="_blank" rel="noreferrer">git客户端</a></p><p>两个工具的安装都是傻瓜式的，请自行安装</p></blockquote><ol><li><p><strong>克隆我的项目</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/codemyhappy/codemyhappy.github.io.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codemyhappy.github.io</span></span></code></pre></div></li><li><p><strong>安装依赖</strong>（需要先安装pnpm）</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pnpm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div></li><li><p><strong>启动开发服务器</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>然后访问 <code>http://localhost:9002</code> 查看效果</p></li><li><p><strong>部署到GitHub Pages</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./deploy.sh</span></span></code></pre></div></li></ol><p>部署过程中会自动生成静态文件，并推送到GitHub Pages。</p><p><img src="`+h+`" alt="alt text"></p><h4 id="项目目录结构" tabindex="-1">项目目录结构 <a class="header-anchor" href="#项目目录结构" aria-label="Permalink to &quot;项目目录结构&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.</span></span>
<span class="line"><span>├── .vitepress/             # VitePress 配置目录</span></span>
<span class="line"><span>├── wwwroot/                # 源代码目录 (VitePress 源文件)</span></span>
<span class="line"><span>│   ├── blog/               # 博客文章目录</span></span>
<span class="line"><span>│   │   ├── index.md        # 博客首页</span></span>
<span class="line"><span>│   │   └── 文章文件...</span></span>
<span class="line"><span>│   ├── index.md            # 首页</span></span>
<span class="line"><span>│   └── public/             # 静态资源目录</span></span>
<span class="line"><span>├── docs/                   # 构建输出目录 (GitHub Pages 部署目录)</span></span>
<span class="line"><span>├── todo-drafts/            # 待发布文章草稿</span></span>
<span class="line"><span>├── components/             # 博客组件目录</span></span>
<span class="line"><span>├── deploy.sh               # 自动化部署脚本</span></span>
<span class="line"><span>├── push-to-remote.sh       # 仅推送到远程仓库，不发版</span></span>
<span class="line"><span>├── package.json            # 项目配置和脚本</span></span>
<span class="line"><span>└── README.md               # 项目说明</span></span></code></pre></div><p>具体的开发流程、更多脚本命令和部署方式，请参阅项目根目录的 README.md 文件，里面有详细的说明。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>静态网站生成器有很多，如Hexo、Jekyll、Hugo、Astro，等等。</p><p>但我这个项目基于Vitepress在背后做了许多的工作，比如自动生成目录、自动生成侧边栏、自动生成导航栏等等。</p><p>当然，如果你只是想要一个非常简单的页面，使用纯HTML/CSS也是可以的。选择哪种方案取决于你的需求和技术水平。</p><h2 id="最后预告一下" tabindex="-1">最后预告一下 <a class="header-anchor" href="#最后预告一下" aria-label="Permalink to &quot;最后预告一下&quot;">​</a></h2><p>这篇文章是github搭建静态主页，系列文章的第二篇，下一篇文章我计划做一个桌面端的APP。</p><p>用这个APP来进一步简化整个流程，类似本文中的第一个方案。关注我吧，敬请期待！</p><p>希望这篇文章能帮助你搭建出一个满意的个人主页！如果你有任何问题，欢迎在评论区交流。</p>`,36)])])}const _=a(o,[["render",r]]);export{m as __pageData,_ as default};
